  ('medical-tech-moex-17808', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '組織檢體染色鏡檢時發現銅幣狀小體（sclerotic bodies），此病人最有可能感染何種黴菌病？', '["孢子絲菌病（sporotrichosis）", "足菌腫（eumycetoma）", "著色芽生菌病（chromoblastomycosis）", "粗球孢子菌病（coccidioidomycosis）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 49, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17809', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '頭癬檢體在Sabouraud’s agar上長出黃棕色絨毛樣菌落，背面呈鮮黃色，鏡檢可見有隔菌絲及許多紡 綞形厚壁粗糙多節的大分生孢子（macroconidia），此菌最有可能為：', '["Epidermophyton floccosum", "Microsporum canis", "Trichophyton mentagrophytes", "Trichosporon cutaneum"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 50, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17810', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '臨床上Shepard’s A7 or A8 agar主要用於分離下列何種病原菌？', '["Coxiella burnetii", "Ureaplasma urealyticum", "Borrelia recurrentis", "Chlamydia pneumoniae"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 51, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17811', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '下列何者最可能影響Bacteroides fragilis 之生長？', '["氧氣（O）", "膽鹽（bile salt）", "Vancomycin", "Kanamycin 2"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 52, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17812', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '下列有關Clostridium perfringens特性之敘述，何者正確？', '["革蘭氏陰性大型桿菌，厭氧培養時容易見到末端芽孢", "生長緩慢，具有運動力", "莢膜抗原是分型依據，可分成8型", "可產生α-toxin，是氣性壞疽（gas gangrene）最常見的致病原"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 53, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17813', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '厭氧革蘭氏陰性桿菌，菌落半透明且有瓊脂凹陷現象（agar pitting），硝酸鹽還原及尿素酶均為陽性， 對kanamycin及colistin敏感，則可假設性鑑定此菌為？', '["Bacteroides fragilis", "Bacteroides ureolyticus", "Fusobacterium nucleatum", "Prevotella intermedia"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 54, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17814', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '有關厭氧菌之實驗室診斷，下列作法何者錯誤？', '["革蘭氏染色改用0.5% basic fuchsin作對比染劑，效果較佳", "痰及咽喉拭子不適合作厭氧培養", "以拭子取得的檢體必需使用厭氧運送裝置", "多數厭氧菌對數期階段對氧的耐受性較強，宜在隔夜培養後從厭氧箱取出來作鑑定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 55, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17815', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '游走性 Proteus 或 Clostridium 可能影響厭氧菌的分離，下列培養基何者可抑制這些菌的游走現象， 又可讓大部分厭氧菌生長？', '["anBAP（anaerobic blood agar）", "PEA（anaerobic phenylethyl alcohol agar）", "BBE（bacteroides bile esculin agar）", "LKV（laked kanamycin-vancomycin blood agar）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 56, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17816', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '下列有關Bordetella pertussis之特性，何項敘述錯誤？', '["引起百日咳（whooping cough）", "Filamentous hemagglutinin及pertussis toxin是非細胞性疫苗的主要成分", "能在一般的blood agar及EMB agar上生長", "在含活性碳的Regan-Lowe medium生長良好"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 57, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17817', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '鑑別Haemophilus spp.時，X因子的需求試驗比較容易發生錯誤，下列試驗何者有助於確認？', '["Catalase test", "Oxidase test", "ALA-porphyrin test", "Whiff test"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 58, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
